mapper.select:
SELECT 
  FROM BL_PRODUCTS p
  LEFT JOIN BL_PRODUCT_ADMIN_FLAGS f ON p.PRODUCT_ID = f.PRODUCT_ID


        AND (p.PRODUCT_NAME LIKE '%' || #{keyword} || '%'
             OR p.BRAND LIKE '%' || #{keyword} || '%')


        AND p.PLATFORM = #{platform}


        AND NVL(f.IS_VISIBLE, 'Y') = #{visible}


        AND NVL(f.EXCLUDE_RECOMMENDATION, 'N') = #{excludeRecommendation}


        AND NVL(f.QUALITY_STATUS, 'NORMAL') = #{qualityStatus}


        AND (p.IMAGE_URL IS NULL OR p.IMAGE_STATUS IS NULL OR p.IMAGE_STATUS != 'found')


 ORDER BY p.PRODUCT_ID DESC
 FETCH FIRST #{size} ROWS ONLY
